import type { GameBounds, GameConfig } from "../../config/index.js";
import type { DepthBand } from "../../schemas/entities/index.js";
import type { TraceSummaryResult } from "./summarize.js";

export type RunContext = {
  readonly seed: string;
  readonly runId?: string;
};

export type AssemblePromptInput = {
  readonly band: DepthBand;
  readonly depth: number;
  readonly config: GameConfig;
  readonly bounds: GameBounds;
  readonly traceFacts: TraceSummaryResult;
  readonly memoryBlock?: string | null;
  readonly runContext: RunContext;
};

/** Character budget guard for assembled Director prompts (~8k tokens). */
export const PROMPT_MAX_CHAR_LENGTH = 32_000;

import { z } from "zod";

import { bounds } from "../../config/index.js";
import { boundedInt } from "../common.js";

export const STATUS_IDS = bounds.statusVocabulary.closedList;

export const StatusIdSchema = z.enum(STATUS_IDS);

export type StatusId = z.infer<typeof StatusIdSchema>;

export const STATUS_DURATION_BOUNDS = bounds.statusVocabulary.durationTurns;

export const statusDurationSchemaFor = (status: StatusId) =>
  boundedInt(STATUS_DURATION_BOUNDS[status]);

export const StatusApplicationSchema = z
  .strictObject({
    status: StatusIdSchema,
    duration: z.number().int(),
  })
  .superRefine((application, ctx) => {
    const durationBounds = STATUS_DURATION_BOUNDS[application.status];

    if (application.duration < durationBounds.min) {
      ctx.addIssue({
        code: "custom",
        path: ["duration"],
        message: `${application.status} duration must be at least ${durationBounds.min}`,
      });
    }

    if (application.duration > durationBounds.max) {
      ctx.addIssue({
        code: "custom",
        path: ["duration"],
        message: `${application.status} duration must be at most ${durationBounds.max}`,
      });
    }
  });

export type StatusApplication = z.infer<typeof StatusApplicationSchema>;

import { z } from "zod";

import { bounds } from "../../config/index.js";
import { nonEmptyString } from "../common.js";
import { EffectBundleSchema, type EffectBundle } from "../vocab/index.js";
import { EntityNameSchema } from "./common.js";

export const TrapDefinitionSchema = z
  .strictObject({
    id: nonEmptyString,
    name: EntityNameSchema,
    hidden: z.literal(true),
    effectBundle: EffectBundleSchema,
  })
  .superRefine((trap, ctx) => {
    enforceStepTrap(trap.effectBundle, ctx);
  });

export type TrapDefinition = z.infer<typeof TrapDefinitionSchema>;

export const TrapDefinitionsForFloorSchema = z
  .array(TrapDefinitionSchema)
  .min(bounds.trapsNpcsQuests.traps.perFloor.min)
  .max(bounds.trapsNpcsQuests.traps.perFloor.max);

const enforceStepTrap = (
  effectBundle: EffectBundle,
  ctx: z.RefinementCtx,
): void => {
  if (effectBundle.trigger.kind !== "step") {
    ctx.addIssue({
      code: "custom",
      path: ["effectBundle", "trigger", "kind"],
      message: "trap effect bundle trigger must be step",
    });
  }
};

